<?php
 namespace WPAICG\ContentWriter\Ajax\Actions\Shared; use WPAICG\Core\AIPKit_OpenAI_Reasoning; if (!defined('ABSPATH')) { exit; } function prepare_ai_params_logic(array $settings): array { $ai_params_override = []; if (isset($settings['ai_temperature'])) { $ai_params_override['temperature'] = floatval($settings['ai_temperature']); } $max_completion_tokens = null; if (isset($settings['max_completion_tokens']) && is_numeric($settings['max_completion_tokens'])) { $max_completion_tokens = absint($settings['max_completion_tokens']); } elseif (isset($settings['max_tokens']) && is_numeric($settings['max_tokens'])) { $max_completion_tokens = absint($settings['max_tokens']); } else { $content_length = isset($settings['content_length']) ? sanitize_key($settings['content_length']) : ''; $length_map = [ 'short' => 2000, 'medium' => 4000, 'long' => 6000, ]; if (isset($length_map[$content_length])) { $max_completion_tokens = $length_map[$content_length]; } } if ($max_completion_tokens) { $ai_params_override['max_completion_tokens'] = $max_completion_tokens; } if (($settings['provider'] ?? '') === 'OpenAI') { $reasoning_effort = AIPKit_OpenAI_Reasoning::normalize_effort_for_model( (string) ($settings['ai_model'] ?? ''), $settings['reasoning_effort'] ?? '' ); if ($reasoning_effort !== '') { $ai_params_override['reasoning'] = ['effort' => $reasoning_effort]; } } elseif (($settings['provider'] ?? '') === 'Ollama') { $reasoning_effort = AIPKit_OpenAI_Reasoning::sanitize_effort($settings['reasoning_effort'] ?? ''); if ($reasoning_effort !== '' && $reasoning_effort !== 'none') { $ai_params_override['reasoning'] = ['effort' => $reasoning_effort]; } } $ai_params_override['top_p'] = null; return $ai_params_override; } 